const output = $('SSH — Listar').first().json.stdout || '';
const files = output.trim().split('\n').filter(f => f && f.endsWith('.html'));
const slugMap = {};
for (const file of files) {
  if (file.endsWith('-termos.html')) {
    const s = file.replace('-termos.html', '');
    if (!slugMap[s]) slugMap[s] = { slug: s, hasMain: false, hasTermos: false, hasPrivacidade: false };
    slugMap[s].hasTermos = true;
  } else if (file.endsWith('-privacidade.html')) {
    const s = file.replace('-privacidade.html', '');
    if (!slugMap[s]) slugMap[s] = { slug: s, hasMain: false, hasTermos: false, hasPrivacidade: false };
    slugMap[s].hasPrivacidade = true;
  } else {
    const s = file.replace('.html', '');
    if (!slugMap[s]) slugMap[s] = { slug: s, hasMain: false, hasTermos: false, hasPrivacidade: false };
    slugMap[s].hasMain = true;
  }
}
const lps = Object.values(slugMap).map(lp => ({
  ...lp,
  url: 'https://' + lp.slug + '.atendimentoweb.com'
}));
return [{ json: { lps } }];
